func TestGRPCService(t *testing.T) {
	t.Parallel()

	defaultTimeout := 30 * time.Second
	ctx, cancel := context.WithTimeout(context.Background(), defaultTimeout)
	t.Cleanup(cancel)

	address := filepath.Join(os.TempDir(), "kmsv2.sock")
